const s="/api";async function a(e,t){const n=await fetch(`${s}${e}`,{...t,headers:{"Content-Type":"application/json",...t==null?void 0:t.headers}});let r;try{r=await n.json()}catch{throw new Error(n.status===0?"网络错误，请确认后端已启动":"响应解析失败")}if(r.code!==200)throw new Error(r.message||"请求失败");return r}const o={get(e){return a(e,{method:"GET"})},post(e,t){return a(e,{method:"POST",body:JSON.stringify(t)})},put(e,t){return a(e,{method:"PUT",body:JSON.stringify(t)})},delete(e){return a(e,{method:"DELETE"})}};export{o as a};
